{"command":"$env:PROD_URL='postgresql://postgres.eqccjfbyrywsqkxxpjvg:ECUCkNBgLLbdamXtAu5uL2QcMhjswfSiJsAxdW9hgaEI26KL9!@aws-1-us-east-1.pooler.supabase.com:5432/postgres'; @'
const { Client } = require('pg');
const docId = '9d09fa89-3a46-465e-a98b-837287c9e22a';
(async () => {
  const c = new Client({ connectionString: process.env.PROD_URL, ssl: { rejectUnauthorized: false } });
  await c.connect();
  try {
    await c.query('begin');
    const q = `with doc_claims as (
      select distinct ce.claim_id
      from claim_evidence ce
      join document_chunks dc on dc.id = ce.source_document_chunk_id
      where dc.document_id = $1::uuid
    ), deleted_sc as (
      delete from section_claims where claim_id in (select claim_id from doc_claims)
      returning section_id, claim_id
    ), gap_matches as (
      select g.id,
        coalesce(jsonb_agg(e.elem) filter (where e.elem in (select claim_id::text from doc_claims)), '[]'::jsonb) as removed_claim_ids,
        coalesce(jsonb_agg(e.elem) filter (where e.elem not in (select claim_id::text from doc_claims)), '[]'::jsonb) as kept_claim_ids
      from gaps g
      cross join lateral jsonb_array_elements_text(coalesce(g.related_claim_ids, '[]'::jsonb)) e(elem)
      where exists (select 1 from doc_claims dc where g.related_claim_ids ? dc.claim_id::text)
      group by g.id
    ), updated_gaps as (
      update gaps g
      set related_claim_ids = gm.kept_claim_ids,
          resolved_by_claim_id = case when g.resolved_by_claim_id in (select claim_id from doc_claims) then null else g.resolved_by_claim_id end,
          updated_at = now()
      from gap_matches gm
      where g.id = gm.id
      returning g.id, gm.removed_claim_ids, g.related_claim_ids as remaining_claim_ids, g.resolved_by_claim_id
    ), deleted_contradictions as (
      delete from contradictions
      where claim_a_id in (select claim_id from doc_claims)
         or claim_b_id in (select claim_id from doc_claims)
         or resolved_by_claim_id in (select claim_id from doc_claims)
         or exists (select 1 from doc_claims dc where contradictions.retrieved_claim_ids ? dc.claim_id::text)
      returning id
    )
    select jsonb_build_object(
      'deleted_section_claims', coalesce((select jsonb_agg(row_to_json(d)) from deleted_sc d), '[]'::jsonb),
      'updated_gaps', coalesce((select jsonb_agg(row_to_json(u)) from updated_gaps u), '[]'::jsonb),
      'deleted_contradictions', coalesce((select jsonb_agg(row_to_json(dc)) from deleted_contradictions dc), '[]'::jsonb)
    ) result`;
    const r = await c.query(q, [docId]);
    const check = await c.query(`with doc_claims as (
      select distinct ce.claim_id
      from claim_evidence ce join document_chunks dc on dc.id = ce.source_document_chunk_id
      where dc.document_id = $1::uuid
    ), sc as (select 1 from section_claims where claim_id in (select claim_id from doc_claims)),
    con as (select 1 from contradictions where claim_a_id in (select claim_id from doc_claims) or claim_b_id in (select claim_id from doc_claims) or resolved_by_claim_id in (select claim_id from doc_claims) or exists (select 1 from doc_claims dc where contradictions.retrieved_claim_ids ? dc.claim_id::text)),
    gr as (select 1 from gaps where resolved_by_claim_id in (select claim_id from doc_claims)),
    gj as (select 1 from gaps where exists (select 1 from doc_claims dc where gaps.related_claim_ids ? dc.claim_id::text))
    select (select count(*)::int from sc) section_claims, (select count(*)::int from con) contradictions, (select count(*)::int from gr) gaps_resolved_by_claim_id, (select count(*)::int from gj) gaps_related_claim_ids`, [docId]);
    await c.query('commit');
    console.log('MUTATION', JSON.stringify(r.rows[0].result, null, 2));
    console.log('POST_BLOCKERS', JSON.stringify(check.rows[0]));
  } catch (e) {
    await c.query('rollback');
    throw e;
  } finally {
    await c.end();
  }
})().catch(e => { console.error(e.stack || e.message); process.exit(1); });
'@ | node","workdir":"C:\repos\oracle","timeout_ms":60000}

{"command":"$env:PROD_URL='postgresql://postgres.eqccjfbyrywsqkxxpjvg:ECUCkNBgLLbdamXtAu5uL2QcMhjswfSiJsAxdW9hgaEI26KL9!@aws-1-us-east-1.pooler.supabase.com:5432/postgres'; @'
const { Client } = require('pg');
const docId = '9d09fa89-3a46-465e-a98b-837287c9e22a';
(async () => {
  const c = new Client({ connectionString: process.env.PROD_URL, ssl: { rejectUnauthorized: false } });
  await c.connect();
  const refs = await c.query(`select tc.table_name, kcu.column_name, tc.constraint_name
    from information_schema.table_constraints tc
    join information_schema.key_column_usage kcu on tc.constraint_name=kcu.constraint_name and tc.table_schema=kcu.table_schema
    join information_schema.constraint_column_usage ccu on ccu.constraint_name=tc.constraint_name and ccu.table_schema=tc.table_schema
    where tc.constraint_type='FOREIGN KEY' and ccu.table_name='claims' and ccu.column_name='id'
    order by tc.table_name, kcu.column_name`);
  console.log('CLAIM_FKS', JSON.stringify(refs.rows));
  const q = `with doc_claims as (
    select distinct ce.claim_id
    from claim_evidence ce join document_chunks dc on dc.id = ce.source_document_chunk_id
    where dc.document_id = $1::uuid
  )
  select mrc.macro_relationship_id, count(*)::int claim_refs, array_agg(mrc.claim_id order by mrc.claim_id) claim_ids
  from macro_relationship_claims mrc
  where mrc.claim_id in (select claim_id from doc_claims)
  group by mrc.macro_relationship_id
  order by mrc.macro_relationship_id`;
  const r = await c.query(q, [docId]);
  console.log('MACRO_RELATIONSHIP_CLAIM_BLOCKERS', JSON.stringify(r.rows, null, 2));
  await c.end();
})().catch(e => { console.error(e.stack || e.message); process.exit(1); });
