const docId='9d09fa89-3a46-465e-a98b-837287c9e22a';
const requestedMap='72ed0ef9-8ea7-4e60-84a3-a7e9236eb7c8';
const latestMap='59cf6272-f658-404a-9ff9-c74b3d9b22f3';
async function gate(c, mapId) {
 const q = `with promoted_claims as (
    select distinct cl.id, cl.map_element_ref, cl.status
    from claims cl
    join claim_evidence ce on ce.claim_id = cl.id
    join document_chunks dc on dc.id = ce.source_document_chunk_id
    where dc.document_id = $1::uuid and cl.status <> 'rejected'
  ), map_elements as (
    select n.elem->>'nodeId' element_id, 'node' element_type from source_workflow_maps m, jsonb_array_elements(m.nodes_json) n(elem) where m.id=$2::uuid
    union all
    select e.elem->>'edgeId' element_id, 'edge' element_type from source_workflow_maps m, jsonb_array_elements(m.edges_json) e(elem) where m.id=$2::uuid
  ), claim_groups as (
    select map_element_ref, count(*)::int claim_count
    from promoted_claims where map_element_ref is not null
    group by map_element_ref
  ) select jsonb_build_object(
    'map_id', $2::text,
    'claim_count', (select count(*)::int from promoted_claims),
    'null_map_element_ref', (select count(*)::int from promoted_claims where map_element_ref is null),
    'map_total', (select count(*)::int from map_elements),
    'map_nodes', (select count(*)::int from map_elements where element_type='node'),
    'map_edges', (select count(*)::int from map_elements where element_type='edge'),
    'evidenced', (select count(distinct me.element_id)::int from map_elements me join promoted_claims pc on pc.map_element_ref = me.element_id),
    'coverage_pct', round(((select count(distinct me.element_id)::numeric from map_elements me join promoted_claims pc on pc.map_element_ref = me.element_id) / nullif((select count(*)::numeric from map_elements),0)) * 100, 2),
    'max_group_size', coalesce((select max(claim_count)::int from claim_groups), 0),
    'elements_with_3_plus', (select count(*)::int from claim_groups where claim_count >= 3),
    'non_null_claim_refs_not_in_map', (select count(*)::int from promoted_claims pc where pc.map_element_ref is not null and not exists (select 1 from map_elements me where me.element_id=pc.map_element_ref)),
    'top_groups', coalesce((select jsonb_agg(row_to_json(g) order by claim_count desc, map_element_ref) from (select * from claim_groups order by claim_count desc, map_element_ref limit 20) g), '[]'::jsonb)
  ) result`;
 const r = await c.query(q,[docId,mapId]);
 return r.rows[0].result;
}
(async()=>{const c=new Client({connectionString:process.env.PROD_URL,ssl:{rejectUnauthorized:false}});await c.connect();const requested=await gate(c,requestedMap); const latest=await gate(c,latestMap); console.log(JSON.stringify({requestedMap:requested, latestValidatedMap:latest}, null, 2)); await c.end();})().catch(e=>{console.error(e.stack||e.message);process.exit(1)});
